headStyles:
body { background: var(--dark-bg); }

/* ── Summary Stats ── */
.stats-bar {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 16px;
  margin-top: -40px;
  position: relative;
  z-index: 2;
}
.stat-card {
  background: rgba(19, 45, 68, 0.5);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 12px;
  padding: 24px 20px;
  text-align: center;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
}
button.stat-card {
  font: inherit;
  color: inherit;
  cursor: pointer;
  appearance: none;
  -webkit-appearance: none;
  transition: transform 0.15s ease, border-color 0.15s ease, background 0.15s ease;
}
button.stat-card:hover {
  transform: translateY(-2px);
  border-color: rgba(255, 255, 255, 0.22);
  background: rgba(19, 45, 68, 0.7);
}
button.stat-card:focus-visible {
  outline: 2px solid var(--text-accent);
  outline-offset: 2px;
}
button.stat-card[aria-pressed="true"] {
  border-color: var(--text-accent);
  box-shadow: 0 0 0 1px var(--text-accent) inset;
}
.stat-card .stat-number {
  font-family: 'Montserrat', sans-serif;
  font-size: 36px;
  font-weight: 800;
  color: var(--text-white);
  line-height: 1;
  margin-bottom: 6px;
}
.stat-card .stat-label {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 1.5px;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.5);
}

/* ── Updated Badge ── */
.updated-badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  background: rgba(255, 255, 255, 0.06);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 20px;
  padding: 6px 14px;
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.5);
  letter-spacing: 0.5px;
  margin-top: 20px;
}
.updated-badge .dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--text-success);
  display: inline-block;
}

/* ── Filter/Controls Bar ── */
.controls-bar {
  position: sticky;
  top: 72px;
  z-index: 100;
  background: rgba(15, 34, 51, 0.88);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
  padding: 16px 0;
  margin-bottom: 32px;
}
.controls-inner {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 12px;
}
.search-input {
  flex: 0 0 220px;
  padding: 8px 14px;
  border-radius: 6px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: rgba(255, 255, 255, 0.06);
  color: var(--text-white);
  font-family: 'Roboto Slab', serif;
  font-size: 14px;
  outline: none;
  transition: border-color 0.2s;
}
.search-input::placeholder { color: rgba(255, 255, 255, 0.35); }
.search-input:focus { border-color: var(--color-blue); }

.pill-group {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
}
.pill {
  font-family: 'Montserrat', sans-serif;
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0.3px;
  padding: 6px 14px;
  border-radius: 20px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: rgba(255, 255, 255, 0.06);
  color: rgba(255, 255, 255, 0.65);
  cursor: pointer;
  transition: all 0.2s;
  white-space: nowrap;
}
.pill:hover { border-color: rgba(255, 255, 255, 0.2); color: var(--text-white); }
.pill.active { background: var(--color-blue); border-color: var(--color-blue); color: var(--text-white); }
.pill.grade-pill.active { border-color: transparent; }

.sort-select {
  padding: 8px 12px;
  border-radius: 6px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: rgba(255, 255, 255, 0.06);
  color: var(--text-white);
  font-family: 'Montserrat', sans-serif;
  font-size: 12px;
  font-weight: 600;
  outline: none;
  cursor: pointer;
}
.sort-select option { background: #1a3a52; color: #fff; }

.results-count {
  font-family: 'Montserrat', sans-serif;
  font-size: 12px;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.4);
  margin-left: auto;
  white-space: nowrap;
}

.controls-divider {
  width: 1px;
  height: 28px;
  background: rgba(255, 255, 255, 0.1);
  flex-shrink: 0;
}

/* ── Legislator Cards ── */
.card-list { padding-bottom: 40px; }

.leg-card {
  background: rgba(19, 45, 68, 0.5);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 12px;
  padding: 20px 24px;
  margin-bottom: 8px;
  cursor: pointer;
  transition: all 0.3s;
}
.leg-card:hover {
  border-color: rgba(255, 255, 255, 0.15);
  transform: translateY(-1px);
}
.leg-card.grade-f {
  background: rgba(220, 38, 38, 0.08);
  border-color: rgba(220, 38, 38, 0.15);
}
.leg-card.grade-f:hover { border-color: rgba(220, 38, 38, 0.3); }
.leg-card.grade-aplus {
  background: rgba(22, 163, 74, 0.08);
  border-color: rgba(22, 163, 74, 0.15);
}
.leg-card.grade-aplus:hover { border-color: rgba(22, 163, 74, 0.3); }

.card-collapsed {
  display: flex;
  align-items: center;
  gap: 20px;
}

.grade-badge {
  width: 48px;
  height: 48px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: 'Montserrat', sans-serif;
  font-weight: 800;
  font-size: 16px;
  color: #fff;
  flex-shrink: 0;
  text-shadow: 0 1px 2px rgba(0,0,0,0.3);
}

.card-center {
  flex: 1;
  min-width: 0;
}
.card-name {
  font-family: 'Montserrat', sans-serif;
  font-weight: 700;
  font-size: 16px;
  color: var(--text-white);
  line-height: 1.3;
}
.card-meta {
  font-family: 'Montserrat', sans-serif;
  font-size: 12px;
  font-weight: 500;
  color: rgba(255, 255, 255, 0.45);
  margin-top: 2px;
}
.card-meta .party-d { color: #60a5fa; }
.card-meta .party-r { color: #f87171; }

.score-bar-wrap {
  margin-top: 8px;
  height: 4px;
  background: rgba(255, 255, 255, 0.06);
  border-radius: 2px;
  overflow: hidden;
  max-width: 280px;
}
.score-bar-fill {
  height: 100%;
  border-radius: 2px;
  transition: width 0.6s ease;
}

.card-right {
  text-align: right;
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: 4px;
}
.card-score-row {
  display: flex;
  align-items: baseline;
  gap: 4px;
}
.card-score {
  font-family: 'Montserrat', sans-serif;
  font-size: 32px;
  font-weight: 800;
  line-height: 1;
  font-variant-numeric: tabular-nums;
}
.card-score-suffix {
  font-family: 'Montserrat', sans-serif;
  font-size: 13px;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.4);
}
.card-grade-label {
  font-family: 'Montserrat', sans-serif;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1.4px;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.55);
}
.card-subscores {
  display: flex;
  gap: 10px;
  margin-top: 4px;
  flex-wrap: wrap;
  justify-content: flex-end;
}
.subscore {
  font-family: 'Montserrat', sans-serif;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.6px;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.45);
  display: inline-flex;
  align-items: center;
  gap: 4px;
}
.subscore .ss-num {
  font-size: 12px;
  font-weight: 800;
  letter-spacing: 0;
  color: rgba(255, 255, 255, 0.85);
  font-variant-numeric: tabular-nums;
  padding: 1px 6px;
  background: rgba(255, 255, 255, 0.06);
  border-radius: 4px;
  min-width: 28px;
  text-align: center;
}
.subscore .ss-num.pos { color: var(--text-success); background: rgba(74, 222, 128, 0.10); }
.subscore .ss-num.neg { color: var(--text-danger);  background: rgba(255, 107, 107, 0.10); }
.subscore .ss-num.zero { color: rgba(255, 255, 255, 0.35); background: rgba(255, 255, 255, 0.04); }
.subscore .ss-num.has  { color: var(--text-white);  background: rgba(255, 255, 255, 0.10); }

.card-chevron {
  flex-shrink: 0;
  width: 20px;
  height: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: rgba(255, 255, 255, 0.3);
  transition: transform 0.3s;
}
.leg-card.expanded .card-chevron { transform: rotate(180deg); }

/* ── Sticky member header when the card is expanded ──
   Keeps the lawmaker's name, grade, and score visible while the
   reader scrolls through the vote/sponsorship breakdown below.
   The per-tally subscore counts on the right are hidden in the
   expanded state because the expanded content shows them in full
   detail just below, and we want the sticky header to be about
   *who* the record belongs to, not the headline tally. */
.leg-card.expanded .card-collapsed {
  position: sticky;
  top: 140px;
  z-index: 20;
  background: rgba(19, 45, 68, 0.97);
  backdrop-filter: blur(14px);
  -webkit-backdrop-filter: blur(14px);
  margin: -24px -24px 0;
  padding: 16px 24px;
  border-radius: 12px 12px 0 0;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}
.leg-card.grade-f.expanded .card-collapsed { background: rgba(60, 22, 22, 0.97); }
.leg-card.grade-aplus.expanded .card-collapsed,
.leg-card.grade-a.expanded .card-collapsed,
.leg-card.grade-aminus.expanded .card-collapsed { background: rgba(15, 50, 28, 0.97); }
.leg-card.expanded .card-subscores { display: none; }
.leg-card.expanded .score-bar-wrap { display: none; }

/* Expanded content */
.card-expanded {
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.4s ease, padding 0.3s ease;
}
.leg-card.expanded .card-expanded {
  max-height: 600px;
  padding-top: 20px;
}
.card-expanded-inner {
  border-top: 1px solid rgba(255, 255, 255, 0.06);
  padding-top: 16px;
}

/* ── Grade math panel (per-card "how this grade was built") ── */
.grade-math {
  background: rgba(0, 0, 0, 0.28);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 12px;
  padding: 18px 20px;
  margin-bottom: 20px;
}
.grade-math-head { margin-bottom: 14px; }
.gm-title {
  font-family: 'Montserrat', sans-serif;
  font-size: 15px;
  font-weight: 800;
  color: var(--text-white);
  margin: 0 0 4px;
  letter-spacing: 0.2px;
}
.gm-subtitle {
  font-size: 12.5px;
  color: rgba(255, 255, 255, 0.55);
  margin: 0;
}
.gm-rows {
  display: flex;
  flex-direction: column;
  gap: 10px;
  margin-bottom: 14px;
}
.gm-row {
  background: rgba(255, 255, 255, 0.02);
  border: 1px solid rgba(255, 255, 255, 0.05);
  border-radius: 8px;
  padding: 10px 14px;
}
.gm-row-head {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  margin-bottom: 4px;
}
.gm-row-label {
  font-family: 'Montserrat', sans-serif;
  font-size: 13px;
  font-weight: 700;
  color: var(--text-white);
  letter-spacing: 0.3px;
}
.gm-row-num {
  font-family: 'Montserrat', sans-serif;
  font-size: 18px;
  font-weight: 800;
}
.gm-row-num-suffix {
  font-size: 12px;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.35);
}
.gm-num-pos { color: var(--text-success); }
.gm-num-neg { color: var(--text-danger); }
.gm-num-zero { color: rgba(255, 255, 255, 0.55); }
.gm-row-explain {
  font-size: 13px;
  line-height: 1.5;
  color: rgba(255, 255, 255, 0.75);
  margin: 0;
}
.gm-pro { color: var(--text-success); font-weight: 700; }
.gm-anti { color: var(--text-danger); font-weight: 700; }

.gm-formula-box {
  background: rgba(19, 45, 68, 0.5);
  border: 1px dashed rgba(255, 255, 255, 0.12);
  border-radius: 10px;
  padding: 14px;
  text-align: center;
  margin-bottom: 10px;
}
.gm-formula-line {
  font-family: 'Montserrat', sans-serif;
  font-size: 15px;
  font-weight: 700;
  color: rgba(255, 255, 255, 0.8);
  letter-spacing: 0.3px;
  margin-bottom: 6px;
}
.gm-formula-line span { font-size: 16px; }
.gm-formula-line .gm-formula-baseline-tag {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.45);
  letter-spacing: 0.4px;
  text-transform: uppercase;
  margin: 0 4px;
}
.gm-formula-grade {
  font-family: 'Montserrat', sans-serif;
  font-size: 13px;
  color: rgba(255, 255, 255, 0.6);
}
.gm-evidence-note {
  font-size: 12.5px;
  color: rgba(255, 255, 255, 0.5);
  font-style: italic;
  margin: 0;
}

.card-breakdown {
  display: flex;
  gap: 24px;
  margin-bottom: 12px;
  flex-wrap: wrap;
}
.breakdown-item {
  font-family: 'Montserrat', sans-serif;
  font-size: 13px;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.6);
}
.breakdown-item strong {
  color: var(--text-white);
  font-weight: 700;
}
.card-notes {
  font-size: 14px;
  line-height: 1.6;
  color: rgba(255, 255, 255, 0.7);
  margin-top: 8px;
}
.card-bills {
  margin-top: 12px;
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}
.bill-tag {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 600;
  padding: 3px 10px;
  border-radius: 4px;
  letter-spacing: 0.3px;
}
.bill-tag.pro { background: rgba(74, 222, 128, 0.12); color: var(--text-success); border: 1px solid rgba(74, 222, 128, 0.2); }
.bill-tag.anti { background: rgba(255, 107, 107, 0.12); color: var(--text-danger); border: 1px solid rgba(255, 107, 107, 0.2); }

/* ── Roll Call Breakdown ── */
.leg-card.expanded .card-expanded {
  /* lift the collapse cap so longer vote tables are not clipped */
  max-height: 2400px;
}
.vote-rollcalls {
  margin-top: 18px;
  border-top: 1px solid rgba(255, 255, 255, 0.06);
  padding-top: 16px;
}
.vote-rollcalls-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 10px;
  margin-bottom: 10px;
}
.vote-rollcalls-title {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 1.5px;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.55);
}
.vote-totals {
  display: flex;
  gap: 14px;
  flex-wrap: wrap;
  font-family: 'Montserrat', sans-serif;
  font-size: 12px;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.65);
}
.vote-totals .vt-pro { color: var(--text-success); }
.vote-totals .vt-anti { color: var(--text-danger); }
.vote-totals .vt-net-pos { color: var(--text-success); }
.vote-totals .vt-net-neg { color: var(--text-danger); }
.vote-totals .vt-net-zero { color: rgba(255, 255, 255, 0.55); }

.vote-row {
  display: grid;
  grid-template-columns: 44px 1fr auto auto;
  align-items: center;
  gap: 12px;
  padding: 10px 12px;
  margin-bottom: 6px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 8px;
}
.vote-row.dir-pro { border-left: 3px solid var(--text-success); }
.vote-row.dir-anti { border-left: 3px solid var(--text-danger); }
.vote-row.dir-neutral { border-left: 3px solid rgba(255, 255, 255, 0.15); }

.vote-cell-vote {
  font-family: 'Montserrat', sans-serif;
  font-size: 13px;
  font-weight: 800;
  text-align: center;
  padding: 4px 0;
  border-radius: 6px;
}
.vote-cell-vote.vote-y { background: rgba(74, 222, 128, 0.14); color: var(--text-success); }
.vote-cell-vote.vote-n { background: rgba(255, 107, 107, 0.14); color: var(--text-danger); }
.vote-cell-vote.vote-nv,
.vote-cell-vote.vote-e,
.vote-cell-vote.vote-na {
  background: rgba(255, 255, 255, 0.06);
  color: rgba(255, 255, 255, 0.45);
}

.vote-cell-bill {
  display: flex;
  flex-direction: column;
  gap: 2px;
  min-width: 0;
}
.vote-cell-bill .vb-label {
  font-family: 'Montserrat', sans-serif;
  font-size: 13px;
  font-weight: 700;
  color: var(--text-white);
}
.vote-cell-bill .vb-sub {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 500;
  color: rgba(255, 255, 255, 0.5);
  letter-spacing: 0.3px;
}

.vote-cell-dir {
  font-family: 'Montserrat', sans-serif;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1px;
  text-transform: uppercase;
  padding: 3px 9px;
  border-radius: 20px;
}
.vote-cell-dir.dir-pro { background: rgba(74, 222, 128, 0.15); color: var(--text-success); }
.vote-cell-dir.dir-anti { background: rgba(255, 107, 107, 0.15); color: var(--text-danger); }
.vote-cell-dir.dir-neutral { background: rgba(255, 255, 255, 0.06); color: rgba(255, 255, 255, 0.4); }

.vote-cell-points {
  font-family: 'Montserrat', sans-serif;
  font-size: 13px;
  font-weight: 700;
  font-variant-numeric: tabular-nums;
  min-width: 52px;
  text-align: right;
}
.vote-cell-points.pts-pos { color: var(--text-success); }
.vote-cell-points.pts-neg { color: var(--text-danger); }
.vote-cell-points.pts-zero { color: rgba(255, 255, 255, 0.4); }

.vote-empty {
  font-family: 'Montserrat', sans-serif;
  font-size: 13px;
  color: rgba(255, 255, 255, 0.5);
  padding: 12px 0 4px;
}

/* Committee vs floor section split inside the expanded card */
.vote-section {
  margin-top: 18px;
}
.vote-section + .vote-section {
  margin-top: 22px;
}
.vote-section-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 10px;
  margin-bottom: 10px;
  padding-bottom: 8px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
}
.vote-section-title {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  font-family: 'Montserrat', sans-serif;
  font-size: 12px;
  font-weight: 800;
  letter-spacing: 1.2px;
  text-transform: uppercase;
  color: var(--text-white);
}
.vote-section-title .vs-tag {
  font-size: 9px;
  font-weight: 700;
  letter-spacing: 1.2px;
  padding: 3px 8px;
  border-radius: 10px;
  background: rgba(255, 255, 255, 0.06);
  color: rgba(255, 255, 255, 0.55);
  border: 1px solid rgba(255, 255, 255, 0.08);
}
.vote-section-title.floor .vs-tag {
  color: #93c5fd;
  background: rgba(96, 165, 250, 0.12);
  border-color: rgba(96, 165, 250, 0.25);
}
.vote-section-title.committee .vs-tag {
  color: #fcd34d;
  background: rgba(251, 191, 36, 0.10);
  border-color: rgba(251, 191, 36, 0.22);
}
.vote-section-tally {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
  font-family: 'Montserrat', sans-serif;
  font-size: 12px;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.65);
}
.vote-section-tally .vt-pro { color: var(--text-success); }
.vote-section-tally .vt-anti { color: var(--text-danger); }
.vote-section-tally .vt-net-pos { color: var(--text-success); }
.vote-section-tally .vt-net-neg { color: var(--text-danger); }
.vote-section-tally .vt-net-zero { color: rgba(255, 255, 255, 0.55); }

@media (max-width: 640px) {
  .vote-row {
    grid-template-columns: 40px 1fr auto;
  }
  .vote-cell-dir { display: none; }
}

/* ── Sponsorship + News blocks (mirror voting record shell) ── */
.record-block {
  margin-top: 18px;
  border-top: 1px solid rgba(255, 255, 255, 0.06);
  padding-top: 16px;
}
.record-block-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 10px;
  margin-bottom: 10px;
}
.record-block-title {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 1.5px;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.55);
}
.record-block-tally {
  display: flex;
  gap: 14px;
  flex-wrap: wrap;
  font-family: 'Montserrat', sans-serif;
  font-size: 12px;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.65);
}

/* Sponsorship rows: role pill, bill label + title, stance pill, link */
.sponsor-row {
  display: grid;
  grid-template-columns: 90px 1fr 90px 80px;
  align-items: center;
  gap: 12px;
  padding: 10px 12px;
  margin-bottom: 6px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 8px;
}
.sponsor-row.dir-pro  { border-left: 3px solid var(--text-success); }
.sponsor-row.dir-anti { border-left: 3px solid var(--text-danger); }
.sponsor-role {
  font-family: 'Montserrat', sans-serif;
  font-size: 10px;
  font-weight: 800;
  letter-spacing: 1px;
  text-transform: uppercase;
  text-align: center;
  padding: 4px 6px;
  border-radius: 6px;
}
.sponsor-role.primary {
  color: #fde68a;
  background: rgba(251, 191, 36, 0.16);
  border: 1px solid rgba(251, 191, 36, 0.3);
}
.sponsor-role.co {
  color: rgba(255, 255, 255, 0.7);
  background: rgba(255, 255, 255, 0.06);
  border: 1px solid rgba(255, 255, 255, 0.12);
}
.sponsor-bill {
  display: flex;
  flex-direction: column;
  gap: 2px;
  min-width: 0;
}
.sponsor-bill .sb-label {
  font-family: 'Montserrat', sans-serif;
  font-size: 13px;
  font-weight: 700;
  color: var(--text-white);
}
.sponsor-bill .sb-sub {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 500;
  color: rgba(255, 255, 255, 0.5);
  letter-spacing: 0.3px;
}
.sponsor-stance {
  font-family: 'Montserrat', sans-serif;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1px;
  text-transform: uppercase;
  text-align: center;
  padding: 3px 9px;
  border-radius: 20px;
}
.sponsor-stance.pro {
  background: rgba(74, 222, 128, 0.15);
  color: var(--text-success);
}
.sponsor-stance.anti {
  background: rgba(255, 107, 107, 0.15);
  color: var(--text-danger);
}
.sponsor-stance.mixed {
  background: rgba(255, 255, 255, 0.06);
  color: rgba(255, 255, 255, 0.55);
}
.sponsor-link {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.6px;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.7);
  text-decoration: none;
  text-align: right;
  white-space: nowrap;
}
.sponsor-link:hover { color: var(--text-white); text-decoration: underline; }

/* News rows: stacked headline + outlet · date + link */
.news-row {
  display: grid;
  grid-template-columns: 1fr auto;
  align-items: start;
  gap: 12px;
  padding: 10px 12px;
  margin-bottom: 6px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-left: 3px solid rgba(255, 255, 255, 0.15);
  border-radius: 8px;
}
.news-headline {
  font-family: 'Montserrat', sans-serif;
  font-size: 13px;
  font-weight: 700;
  color: var(--text-white);
  line-height: 1.4;
}
.news-meta {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 500;
  color: rgba(255, 255, 255, 0.55);
  letter-spacing: 0.3px;
  margin-top: 3px;
}
.news-link {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.6px;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.7);
  text-decoration: none;
  white-space: nowrap;
}
.news-link:hover { color: var(--text-white); text-decoration: underline; }

.record-empty {
  font-family: 'Montserrat', sans-serif;
  font-size: 13px;
  color: rgba(255, 255, 255, 0.5);
  padding: 12px 0 4px;
}

@media (max-width: 640px) {
  .sponsor-row {
    grid-template-columns: 70px 1fr auto;
  }
  .sponsor-row .sponsor-stance { display: none; }
}

/* ── How We Score (top-of-page explainer) ── */
.how-we-score {
  background: linear-gradient(180deg, rgba(19, 45, 68, 0.6) 0%, rgba(19, 45, 68, 0.35) 100%);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 16px;
  overflow: hidden;
}
.hws-toggle {
  width: 100%;
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 18px 24px;
  background: transparent;
  border: 0;
  cursor: pointer;
  color: inherit;
  text-align: left;
}
.hws-toggle-text { display: flex; flex-direction: column; gap: 2px; }
.hws-eyebrow {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 2px;
  text-transform: uppercase;
  color: var(--text-accent);
}
.hws-toggle-title {
  font-family: 'Montserrat', sans-serif;
  font-size: 16px;
  font-weight: 700;
  color: var(--text-white);
}
.hws-chevron {
  margin-left: auto;
  color: rgba(255, 255, 255, 0.4);
  transition: transform 0.3s;
}
.hws-toggle[aria-expanded="true"] .hws-chevron { transform: rotate(180deg); }
.hws-body {
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.5s ease;
}
.hws-body.open { max-height: 1800px; }
.hws-body > * {
  padding-left: 28px;
  padding-right: 28px;
}
.hws-body > *:last-child { padding-bottom: 24px; }
.hws-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 12px;
  margin: 0 0 18px;
}
.hws-card {
  background: rgba(0, 0, 0, 0.25);
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 10px;
  padding: 14px 16px;
}
.hws-num {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 22px;
  height: 22px;
  border-radius: 50%;
  background: var(--text-accent);
  color: #0c1a2b;
  font-size: 12px;
  font-weight: 800;
  margin-right: 8px;
  vertical-align: middle;
}
.hws-card-title {
  font-family: 'Montserrat', sans-serif;
  font-size: 14px;
  font-weight: 700;
  color: var(--text-white);
  margin: 0 0 8px;
}
.hws-card-body {
  font-size: 13.5px;
  line-height: 1.55;
  color: rgba(255, 255, 255, 0.72);
  margin: 0;
}
.hws-method-link {
  color: var(--text-accent);
  font-weight: 700;
  text-decoration: none;
  margin-left: 6px;
  border-bottom: 1px dashed var(--text-accent);
  padding-bottom: 1px;
}
.hws-formula {
  background: rgba(0, 0, 0, 0.35);
  border: 1px dashed rgba(255, 255, 255, 0.12);
  border-radius: 12px;
  padding: 18px;
  text-align: center;
}
.hws-formula-line {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  align-items: center;
  justify-content: center;
  font-family: 'Montserrat', sans-serif;
  font-size: 16px;
  font-weight: 700;
  color: var(--text-white);
}
.hws-eq { color: var(--text-accent); }
.hws-eq-equals { color: rgba(255, 255, 255, 0.4); }
.hws-eq-block { letter-spacing: 0.5px; }
.hws-formula-key {
  display: flex;
  flex-wrap: wrap;
  gap: 18px;
  justify-content: center;
  margin-top: 12px;
  font-size: 13px;
  color: rgba(255, 255, 255, 0.6);
}
.hws-formula-key span strong { font-size: 16px; margin-right: 4px; }
.hws-tip {
  margin: 18px 0 0;
  text-align: center;
  font-size: 13px;
  color: rgba(255, 255, 255, 0.55);
  font-style: italic;
}
@media (max-width: 720px) {
  .hws-grid { grid-template-columns: 1fr; }
}

/* ── Methodology (bottom CTA) ── */
.methodology {
  padding: 40px 0 80px;
}
.methodology-cta {
  display: flex;
  flex-wrap: wrap;
  gap: 20px;
  align-items: center;
  justify-content: space-between;
  padding: 24px 28px;
  background: rgba(19, 45, 68, 0.5);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 12px;
}
.methodology-cta-btn {
  display: inline-block;
  padding: 12px 22px;
  background: var(--text-accent);
  color: #0c1a2b;
  font-family: 'Montserrat', sans-serif;
  font-size: 14px;
  font-weight: 700;
  text-decoration: none;
  border-radius: 8px;
  transition: transform 0.15s, box-shadow 0.15s;
  white-space: nowrap;
}
.methodology-cta-btn:hover { transform: translateY(-1px); box-shadow: 0 4px 14px rgba(0,0,0,0.3); }
.grade-table {
  width: 100%;
  border-collapse: collapse;
  margin: 12px 0;
}
.grade-table th {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: rgba(255, 255, 255, 0.4);
  text-align: left;
  padding: 8px 12px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.08);
}
.grade-table td {
  font-family: 'Montserrat', sans-serif;
  font-size: 13px;
  font-weight: 600;
  padding: 8px 12px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.04);
  color: rgba(255, 255, 255, 0.7);
}
.grade-table .grade-cell {
  font-weight: 800;
  font-size: 15px;
}

/* ── Hero Methodology Link (top of page) ── */
.hero-method-link-row {
  margin: 14px 0 0 0;
}
.hero-method-link {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-family: 'Montserrat', sans-serif;
  font-size: 13px;
  font-weight: 600;
  color: var(--text-accent);
  text-decoration: none;
  padding: 6px 0;
  border-bottom: 1px solid rgba(255,255,255,0.15);
  transition: color 0.15s, border-color 0.15s;
}
.hero-method-link:hover {
  color: #fff;
  border-bottom-color: var(--text-accent);
}
.hero-method-link svg { transition: transform 0.15s; }
.hero-method-link:hover svg { transform: translateY(2px); }

/* ── Stats Hint ── */
.stats-hint {
  margin: 10px 4px 0;
  font-family: 'Montserrat', sans-serif;
  font-size: 12px;
  color: rgba(255,255,255,0.45);
  letter-spacing: 0.3px;
  transition: color 0.2s ease;
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 12px;
}
.stats-hint.filtered {
  color: var(--text-accent, #fbbf24);
  font-weight: 600;
}
.stats-hint .sh-text { flex: 1 1 auto; min-width: 0; }
.stats-reset {
  display: none;
  align-items: center;
  gap: 6px;
  padding: 6px 12px;
  background: rgba(251, 191, 36, 0.12);
  border: 1px solid rgba(251, 191, 36, 0.45);
  border-radius: 999px;
  color: var(--text-accent, #fbbf24);
  font-family: 'Montserrat', sans-serif;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.4px;
  text-transform: uppercase;
  cursor: pointer;
  transition: background 0.15s ease, transform 0.1s ease, border-color 0.15s ease;
}
.stats-hint.filtered .stats-reset { display: inline-flex; }
.stats-reset:hover {
  background: rgba(251, 191, 36, 0.22);
  border-color: rgba(251, 191, 36, 0.7);
}
.stats-reset:active { transform: scale(0.96); }
.stats-reset svg { width: 12px; height: 12px; }

/* Subtle pulse on stat numbers when they change after a filter. */
@keyframes statPulse {
  0% { transform: scale(1); }
  35% { transform: scale(1.08); }
  100% { transform: scale(1); }
}
.stat-number {
  display: inline-block;
  transform-origin: left center;
  transition: color 0.15s ease;
}
.stat-number.pulse { animation: statPulse 0.45s cubic-bezier(0.25, 1.4, 0.4, 1); }
.stat-card { transition: transform 0.15s ease, border-color 0.15s ease; }
.stat-card:hover { transform: translateY(-2px); }

/* ── Methodology (in-page summary) ── */
.methodology-full {
  padding: 32px 0 80px;
  scroll-margin-top: 88px;
}
.m-hero { margin-bottom: 28px; }
.m-h1 {
