/* ── No Results ── */
.no-results {
  text-align: center;
  padding: 60px 20px;
  color: rgba(255, 255, 255, 0.4);
  font-family: 'Montserrat', sans-serif;
  font-size: 15px;
  font-weight: 500;
  display: none;
}

/* ── Responsive ── */
@media (max-width: 768px) {
  .controls-inner { gap: 8px; }
  .search-input { flex: 1 1 100%; }
  .controls-divider { display: none; }
  .results-count { margin-left: 0; flex: 1 1 100%; text-align: left; }
  .card-collapsed { flex-wrap: wrap; gap: 12px; }
  .card-center { flex: 1 1 calc(100% - 80px); order: 1; }
  .grade-badge { order: 0; }
  .card-right { order: 2; flex: 1 1 100%; text-align: left; display: flex; align-items: center; gap: 16px; }
  .card-score { font-size: 22px; }
  .card-chevron { order: 3; }
  .score-bar-wrap { max-width: 100%; }
  .card-subscores { gap: 8px; }
  .card-breakdown { gap: 12px; }

  /* ── Mobile sticky stats bar (4 boxes follow you) ── */
  .stats-bar {
    position: fixed;
    top: 64px;
    left: 0;
    right: 0;
    z-index: 95;
    margin: 0;
    padding: 8px 12px;
    grid-template-columns: repeat(4, 1fr);
    gap: 4px;
    background: rgba(15, 34, 51, 0.96);
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    border-bottom: 1px solid rgba(255, 255, 255, 0.08);
    border-radius: 0;
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.3);
  }
  .stats-bar .stat-card {
    padding: 4px 4px;
    border-radius: 6px;
    border: none;
    background: transparent;
    backdrop-filter: none;
    -webkit-backdrop-filter: none;
    box-shadow: none;
  }
  .stats-bar .stat-card .stat-number {
    font-size: 18px;
    margin-bottom: 1px;
  }
  .stats-bar .stat-card .stat-label {
    font-size: 7.5px;
    letter-spacing: 0.4px;
    line-height: 1.2;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  /* Push content down to clear the fixed stats bar */
  .stats-hint { margin-top: 60px; }
  body { scroll-padding-top: 144px; }
  .controls-bar { top: 132px; }

  /* ── Sticky member name when expanded ── */
  .leg-card.expanded .card-collapsed {
    position: sticky;
    top: 200px;
    z-index: 30;
    background: rgba(19, 45, 68, 0.97);
    backdrop-filter: blur(14px);
    -webkit-backdrop-filter: blur(14px);
    margin: -16px -16px 0;
    padding: 12px 16px;
    border-radius: 12px 12px 0 0;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
  }
  .leg-card.grade-f.expanded .card-collapsed {
    background: rgba(60, 22, 22, 0.97);
  }
  .leg-card.grade-d.expanded .card-collapsed {
    background: rgba(56, 32, 22, 0.97);
  }
  .leg-card.grade-aplus.expanded .card-collapsed,
  .leg-card.grade-a.expanded .card-collapsed,
  .leg-card.grade-aminus.expanded .card-collapsed {
    background: rgba(15, 50, 28, 0.97);
  }

  /* Full record visible on mobile - no height clamp */
  .leg-card.expanded .card-expanded {
    max-height: none;
    padding-top: 16px;
  }
}
@media (max-width: 480px) {
  .stat-card { padding: 16px 12px; }
  .leg-card { padding: 16px; }
  .pill { font-size: 11px; padding: 5px 10px; }

  /* Tighten mobile sticky stats bar on small phones */
  .stats-bar { padding: 6px 8px; gap: 3px; }
  .stats-bar .stat-card .stat-number { font-size: 16px; }
  .stats-bar .stat-card .stat-label { font-size: 6.5px; letter-spacing: 0.3px; }
  body { scroll-padding-top: 130px; }
  .controls-bar { top: 122px; }
  .leg-card.expanded .card-collapsed { top: 184px; }
}

/* ── Share actions (per-card) ── */
.card-share {
  margin-top: 18px;
  padding-top: 14px;
  border-top: 1px dashed rgba(255, 255, 255, 0.08);
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  align-items: center;
}
.card-share-label {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 1.4px;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.55);
  margin-right: 6px;
}
.share-btn {
  font-family: 'Montserrat', sans-serif;
  font-size: 12px;
  font-weight: 600;
  padding: 7px 14px;
  border-radius: 6px;
  border: 1px solid rgba(255, 255, 255, 0.14);
  background: rgba(255, 255, 255, 0.04);
  color: rgba(255, 255, 255, 0.85);
  cursor: pointer;
  transition: background 0.15s, border-color 0.15s, transform 0.1s;
  display: inline-flex;
  align-items: center;
  gap: 6px;
}
.share-btn:hover { background: rgba(255, 255, 255, 0.10); border-color: rgba(255, 255, 255, 0.28); }
.share-btn:active { transform: translateY(1px); }
.share-btn.fb     { border-color: rgba(24, 119, 242, 0.45); color: #6aa3f7; }
.share-btn.fb:hover     { background: rgba(24, 119, 242, 0.12); }
.share-btn.tw     { border-color: rgba(255, 255, 255, 0.32); color: #fff; }
.share-btn.ig     { border-color: rgba(225, 48, 108, 0.5); color: #f178b6; }
.share-btn.ig:hover     { background: rgba(225, 48, 108, 0.12); }
.share-btn.copy   { border-color: rgba(255, 255, 255, 0.18); }

/* ── Chamber breakdown tiles ── */
.chamber-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
}
@media (max-width: 720px) {
  .chamber-grid { grid-template-columns: 1fr; }
}
.chamber-tile {
  background: rgba(19, 45, 68, 0.5);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 12px;
  padding: 22px 24px;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
}
.ct-head {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  margin-bottom: 14px;
}
.ct-title {
  font-family: 'Montserrat', sans-serif;
  font-size: 16px;
  font-weight: 700;
  color: var(--text-white);
}
.ct-meta {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 1.2px;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.45);
}
.ct-avg {
  display: flex;
  align-items: baseline;
  gap: 10px;
  margin-bottom: 18px;
}
.ct-avg-num {
  font-family: 'Montserrat', sans-serif;
  font-size: 32px;
  font-weight: 800;
  color: var(--text-white);
  line-height: 1;
}
.ct-avg-suffix {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 1px;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.5);
}
.ct-bars {
  display: grid;
  grid-template-columns: repeat(6, 1fr);
  gap: 6px;
}
.ct-bar {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
  cursor: pointer;
  padding: 4px 2px;
  border-radius: 6px;
  transition: background 0.15s;
}
.ct-bar:hover { background: rgba(255, 255, 255, 0.04); }
.ct-bar-fill-wrap {
  width: 100%;
  height: 56px;
  background: rgba(255, 255, 255, 0.05);
  border-radius: 4px;
  position: relative;
  overflow: hidden;
}
.ct-bar-fill {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  transition: height 0.6s cubic-bezier(0.2, 0.7, 0.3, 1);
}
.ct-bar-grade {
  font-family: 'Montserrat', sans-serif;
  font-size: 12px;
  font-weight: 700;
  color: rgba(255, 255, 255, 0.7);
}
.ct-bar-count {
  font-family: 'Montserrat', sans-serif;
  font-size: 10px;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.5);
}

/* ── Leaderboards ── */
.leaderboard-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
}
@media (max-width: 720px) {
  .leaderboard-grid { grid-template-columns: 1fr; }
}
.leaderboard {
  background: rgba(19, 45, 68, 0.5);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 12px;
  overflow: hidden;
}
.lb-head {
  padding: 16px 20px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.08);
  background: rgba(255, 255, 255, 0.02);
}
.lb-head-pos { border-left: 3px solid var(--text-success); }
.lb-head-neg { border-left: 3px solid var(--text-danger); }
.lb-head h3 {
  font-family: 'Montserrat', sans-serif;
  font-size: 15px;
  font-weight: 700;
  color: var(--text-white);
  margin: 0 0 4px;
}
.lb-sub {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 500;
  letter-spacing: 0.5px;
  color: rgba(255, 255, 255, 0.45);
}
.lb-list {
  list-style: none;
  padding: 8px 0;
  margin: 0;
}
.lb-item {
  display: grid;
  grid-template-columns: 32px 1fr auto auto;
  gap: 12px;
  align-items: center;
  padding: 10px 20px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.04);
  cursor: pointer;
  text-decoration: none;
  color: inherit;
  transition: background 0.15s;
}
.lb-item:last-child { border-bottom: none; }
.lb-item:hover { background: rgba(255, 255, 255, 0.04); }
.lb-rank {
  font-family: 'Montserrat', sans-serif;
  font-size: 13px;
  font-weight: 800;
  color: rgba(255, 255, 255, 0.4);
  text-align: center;
}
.lb-name {
  font-family: 'Montserrat', sans-serif;
  font-size: 14px;
  font-weight: 600;
  color: var(--text-white);
}
.lb-meta {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  color: rgba(255, 255, 255, 0.5);
  margin-top: 2px;
}
.lb-score {
  font-family: 'Montserrat', sans-serif;
  font-size: 16px;
  font-weight: 800;
  text-align: right;
}
.lb-grade {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 800;
  padding: 4px 8px;
  border-radius: 4px;
  color: #fff;
  min-width: 28px;
  text-align: center;
}

/* ── Keyboard hint ── */
.kbd-hint {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  margin-left: 8px;
  font-family: 'Montserrat', sans-serif;
  font-size: 10px;
  color: rgba(255, 255, 255, 0.35);
}
.kbd-hint kbd {
  font-family: inherit;
  font-size: 10px;
  font-weight: 700;
  padding: 2px 5px;
  background: rgba(255, 255, 255, 0.08);
  border: 1px solid rgba(255, 255, 255, 0.12);
  border-bottom-width: 2px;
  border-radius: 3px;
  color: rgba(255, 255, 255, 0.7);
}

/* ── Print-friendly styles ── */
@media print {
  body { background: #fff; color: #000; }
  .controls-bar, .card-share, .updated-badge, .methodology, #site-header, #site-footer,
  .leaderboard-grid, .chamber-grid, .stats-bar { display: none !important; }
  .leg-card {
    background: #fff !important;
    border: 1px solid #999 !important;
    page-break-inside: avoid;
    margin-bottom: 8px !important;
  }
  .leg-card .card-expanded { display: none !important; }
  .card-name, .card-meta, .card-grade-label { color: #000 !important; }
  .card-score { color: #000 !important; }
  a { color: #000 !important; text-decoration: none !important; }
  .subpage-hero { padding: 12px 0 !important; }
  .subpage-hero h1 { color: #000 !important; }
  .subpage-hero p { color: #333 !important; }
}

