document.addEventListener('DOMContentLoaded', function() {

  /* ── Combine data ── */
  var allMembers = [];
  HOUSE_MEMBERS.forEach(function(m) {
    var score = calcScore(m);
    var grade = calcGrade(score);
    allMembers.push({
      d: m.d, name: m.name, party: m.party, v: m.v, s: m.s, n: m.n,
      notes: m.notes, chamber: 'House', score: score, grade: grade
    });
  });
  SENATE_MEMBERS.forEach(function(m) {
    var score = calcScore(m);
    var grade = calcGrade(score);
    allMembers.push({
      d: m.d, name: m.name, party: m.party, v: m.v, s: m.s, n: m.n,
      notes: m.notes, chamber: 'Senate', score: score, grade: grade
    });
  });

  /* ── Bill count: shared by every render. ──
     Counts current editorial bills (keyed by `id` in SCORED_BILLS) plus
     any historical bill with a recorded roll call (keyed by `billSlug`
     in ROLL_CALLS). Stays static regardless of filter state. */
  var _billSet = {};
  SCORED_BILLS.forEach(function(b) {
    var key = b && (b.id || b.slug);
    if (key) _billSet[key] = true;
  });
  if (typeof ROLL_CALLS !== 'undefined' && ROLL_CALLS && ROLL_CALLS.length) {
    for (var _rcI = 0; _rcI < ROLL_CALLS.length; _rcI++) {
      var _slug = ROLL_CALLS[_rcI].billSlug;
      if (_slug) _billSet[_slug] = true;
    }
  }
  var BILL_COUNT = 0;
  for (var _k in _billSet) { if (Object.prototype.hasOwnProperty.call(_billSet, _k)) BILL_COUNT++; }

  /* ── Live stats bar: re-rendered on every filter change. ──
     Four cards at the top double as filter buttons: click "Champions"
     to jump to grade=A+, click "Hostile" to jump to grade=F, click
     "Legislators Scored" to clear all filters. Numbers pulse briefly
     when their value changes so the bar feels alive. */
  function _setStatNumber(id, val) {
    var el = document.getElementById(id);
    if (!el) return;
    var prev = el.textContent;
    var next = String(val);
    if (prev !== next) {
      el.textContent = next;
      el.classList.remove('pulse');
      /* Force reflow so the animation re-fires on rapid changes. */
      void el.offsetWidth;
      el.classList.add('pulse');
    }
  }
  function renderStats(members) {
    var championCount = 0, hostileCount = 0;
    members.forEach(function(m) {
      var g = m.grade.grade;
      if (g === 'A+') championCount++;
      if (g === 'F')  hostileCount++;
    });
    _setStatNumber('stat-total', members.length);
    _setStatNumber('stat-champions', championCount);
    _setStatNumber('stat-hostile', hostileCount);
    _setStatNumber('stat-bills', BILL_COUNT);

    var hint = document.getElementById('stats-hint');
    var hintText = document.getElementById('stats-hint-text');
    if (hint && hintText) {
      if (members.length === allMembers.length) {
        hintText.textContent = 'Showing the full General Assembly. Filter below to see these numbers shift.';
        hint.classList.remove('filtered');
      } else {
        hintText.textContent = 'Showing ' + members.length + ' of ' + allMembers.length +
          ' lawmakers based on your filters.';
        hint.classList.add('filtered');
      }
    }
  }

  /* ── Updated badge ── */
  document.getElementById('updated-text').textContent =
    'Last updated ' + SCORECARD_UPDATED.date + ' at ' + SCORECARD_UPDATED.time;

  /* ── Methodology grade table (built from GRADE_SCALE) ── */
  (function renderMethodologyGradeTable() {
    var tbl = document.getElementById('m-grade-table');
    if (!tbl) return;
    var html = '<thead><tr><th>Grade</th><th>Label</th><th>Score Range</th></tr></thead><tbody>';
    GRADE_SCALE.forEach(function(g, i) {
      var maxVal = i === 0 ? 100 : GRADE_SCALE[i - 1].min - 1;
      html += '<tr>' +
        '<td><span class="mg-letter" style="color:' + g.color + '">' + g.grade + '</span></td>' +
        '<td>' + g.label + '</td>' +
        '<td>' + g.min + '&ndash;' + maxVal + '</td>' +
      '</tr>';
    });
    html += '</tbody>';
    tbl.innerHTML = html;
  }());

  /* ── Chamber breakdown tiles ── */
  function _gradeColor(letter) {
    for (var i = 0; i < GRADE_SCALE.length; i++) {
      if (GRADE_SCALE[i].grade === letter) return GRADE_SCALE[i].color;
    }
    return 'rgba(255,255,255,0.4)';
  }
  function _renderChamberTile(chamber, avgEl, countEl, barsEl) {
    var members = allMembers.filter(function(m) { return m.chamber === chamber; });
    if (countEl) countEl.textContent = members.length;
    var sum = 0;
    var dist = { 'A+': 0, 'A': 0, 'B': 0, 'C': 0, 'D': 0, 'F': 0 };
    members.forEach(function(m) {
      sum += m.score;
      if (dist.hasOwnProperty(m.grade.grade)) dist[m.grade.grade]++;
    });
    var avg = members.length ? Math.round(sum / members.length) : 0;
    var avgGrade = calcGrade(avg);
    if (avgEl) {
      avgEl.textContent = avgGrade.grade + ' (' + avg + ')';
      avgEl.style.color = avgGrade.color;
    }
    var maxCount = 1;
    for (var g in dist) { if (dist[g] > maxCount) maxCount = dist[g]; }
    var barsHtml = '';
    ['A+', 'A', 'B', 'C', 'D', 'F'].forEach(function(letter) {
      var count = dist[letter];
      var pct = Math.round((count / maxCount) * 100);
      var color = _gradeColor(letter);
      barsHtml +=
        '<div class="ct-bar" data-chamber="' + chamber + '" data-grade="' + letter + '" title="Filter to ' + chamber + ' &middot; ' + letter + '">' +
          '<div class="ct-bar-fill-wrap"><div class="ct-bar-fill" style="background:' + color + '; height:' + pct + '%"></div></div>' +
          '<div class="ct-bar-grade" style="color:' + color + '">' + letter + '</div>' +
          '<div class="ct-bar-count">' + count + '</div>' +
        '</div>';
    });
    if (barsEl) barsEl.innerHTML = barsHtml;
  }
  _renderChamberTile('House', document.getElementById('ct-house-avg'), document.getElementById('ct-house-count'), document.getElementById('ct-house-bars'));
  _renderChamberTile('Senate', document.getElementById('ct-senate-avg'), document.getElementById('ct-senate-count'), document.getElementById('ct-senate-bars'));

  /* ── Leaderboards (top 5 / bottom 5) ── */
  function _renderLeaderboard(targetId, members) {
    var container = document.getElementById(targetId);
    if (!container) return;
    container.innerHTML = members.map(function(m, idx) {
      var partyLabel = m.party === 'D' ? 'D' : 'R';
      var slug = (window.OPP_SHARE && typeof window.OPP_SHARE.slugify === 'function')
        ? window.OPP_SHARE.slugify(m) : '';
      var href = slug ? '?rep=' + encodeURIComponent(slug) + '#card-list' : '#card-list';
      return '<li><a class="lb-item" href="' + href + '" data-name="' + m.name.replace(/"/g, '&quot;') + '">' +
        '<div class="lb-rank">' + (idx + 1) + '</div>' +
        '<div>' +
          '<div class="lb-name">' + m.name + '</div>' +
          '<div class="lb-meta">' + m.chamber + ' D' + m.d + ' &middot; ' + partyLabel + '</div>' +
        '</div>' +
        '<div class="lb-score" style="color:' + m.grade.color + '">' + m.score + '</div>' +
        '<div class="lb-grade" style="background:' + m.grade.color + '">' + m.grade.grade + '</div>' +
      '</a></li>';
    }).join('');
  }
  var sortedAsc = allMembers.slice().sort(function(a, b) { return a.score - b.score || a.name.localeCompare(b.name); });
  var sortedDesc = allMembers.slice().sort(function(a, b) { return b.score - a.score || a.name.localeCompare(b.name); });
  _renderLeaderboard('lb-champions', sortedDesc.slice(0, 5));
  _renderLeaderboard('lb-hostiles', sortedAsc.slice(0, 5));

  /* Click chamber bar -> set chamber + grade filter, scroll to results */
  document.querySelectorAll('.ct-bar').forEach(function(bar) {
    bar.addEventListener('click', function() {
      var ch = bar.getAttribute('data-chamber');
      var gr = bar.getAttribute('data-grade');
      _setChamberFilter(ch);
      _setGradeFilter(gr);
      applyFilters();
      var list = document.getElementById('card-list');
      if (list) list.scrollIntoView({ behavior: 'smooth', block: 'start' });
    });
  });

  /* ── Parse bill references from notes ── */
  function parseBills(notes) {
    var found = [];
    if (!notes) return found;
    SCORED_BILLS.forEach(function(b) {
      if (notes.indexOf(b.bill) !== -1) {
        found.push(b);
      }
    });
    return found;
  }

  /* ── Render cards ── */
  var cardList = document.getElementById('card-list');
  var noResults = document.getElementById('no-results');

  /* Build a chamber-normalized legislator object for voting-records.js.
     The resolver expects chamber as lowercase "house"|"senate"; our
     renderCards member uses display-cased "House"/"Senate". */
  function _votingLegislator(m) {
    return {
      d: m.d,
      party: m.party,
      chamber: (m.chamber || '').toString().toLowerCase()
    };
  }

  function _voteCellClass(v) {
    if (v === 'Y') return 'vote-y';
    if (v === 'N') return 'vote-n';
    if (v === 'NV') return 'vote-nv';
    if (v === 'E') return 'vote-e';
    return 'vote-na';
  }

  function _voteCellLabel(v) {
    if (v === 'Y' || v === 'N' || v === 'NV' || v === 'E') return v;
    return '—';
  }

  function _stageLabel(stage) {
    if (!stage) return '';
    return stage.charAt(0).toUpperCase() + stage.slice(1);
  }

  function _ptsClass(p) {
    if (p > 0) return 'pts-pos';
    if (p < 0) return 'pts-neg';
    return 'pts-zero';
  }

  function _formatPoints(p) {
    if (p === 0) return '0';
    var sign = p > 0 ? '+' : '';
    /* show one decimal only when non-integer */
    return sign + (Math.abs(p) % 1 === 0 ? p.toFixed(0) : p.toFixed(2));
  }

  function _netClass(n) {
    if (n > 0) return 'vt-net-pos';
    if (n < 0) return 'vt-net-neg';
    return 'vt-net-zero';
  }

  /* Render one bucket of roll-call rows (e.g., all floor votes) as a
     vote-section block with its own tally. Returns "" if rows is
     empty (we hide empty sections rather than showing zeroes). */
  function _renderVoteSection(opts) {
    var rows = opts.rows || [];
    var tally = opts.tally || { proVotes: 0, antiVotes: 0, neutralVotes: 0, net: 0 };
    var titleClass = opts.kind || '';
    var heading = opts.heading || 'Votes';
    var tag = opts.tag || '';
    var emptyMsg = opts.emptyMsg || 'No tracked votes in this category.';

    var head =
      '<div class="vote-section-head">' +
        '<div class="vote-section-title ' + titleClass + '">' +
          heading +
          (tag ? '<span class="vs-tag">' + tag + '</span>' : '') +
        '</div>' +
        '<div class="vote-section-tally">' +
          '<span class="vt-pro">Pro-equality: ' + tally.proVotes + '</span>' +
          '<span class="vt-anti">Anti-equality: ' + tally.antiVotes + '</span>' +
          '<span class="' + _netClass(tally.net) + '">Net: ' + _formatPoints(tally.net) + '</span>' +
        '</div>' +
      '</div>';

    if (!rows.length) {
      return '<div class="vote-section">' + head +
        '<div class="vote-empty">' + emptyMsg + '</div>' +
      '</div>';
    }

    var body = '';
    rows.forEach(function(r) {
      var rc = r.rollCall;
      var ptsFmt = _formatPoints(r.points);
      var rowDirClass = 'dir-' + r.direction;
      body +=
        '<div class="vote-row ' + rowDirClass + '">' +
          '<div class="vote-cell-vote ' + _voteCellClass(r.vote) + '">' + _voteCellLabel(r.vote) + '</div>' +
          '<div class="vote-cell-bill">' +
            '<div class="vb-label">' + rc.billLabel + ' &middot; ' + rc.billTitle + '</div>' +
            '<div class="vb-sub">' + rc.label + ' &middot; ' + rc.voteDate + '</div>' +
          '</div>' +
          '<div class="vote-cell-dir ' + rowDirClass + '">' + r.direction + '</div>' +
          '<div class="vote-cell-points ' + _ptsClass(r.points) + '">' + ptsFmt + '</div>' +
        '</div>';
    });

    return '<div class="vote-section">' + head + body + '</div>';
  }

  /* Returns the full "Voting Record" section HTML for a legislator, or
     a minimal empty-state message when no eligible roll calls exist
     (e.g. a member seated after all tracked votes). Floor and
     committee votes are rendered as separate sections so the visual
     distinction matches the methodology. */
  function renderVoteBreakdown(m) {
    var hasGrouped = (typeof getVoteBreakdownByStage === 'function' && typeof summarizeVotesByStage === 'function');
    if (!hasGrouped && (typeof getVoteBreakdown !== 'function' || typeof summarizeVotes !== 'function')) {
      return '';
    }
    var leg = _votingLegislator(m);

    var grouped = hasGrouped ? getVoteBreakdownByStage(leg) : null;
    var totals  = hasGrouped ? summarizeVotesByStage(leg)  : null;

    // Fallback to the old flat shape if stage helpers aren't loaded.
    if (!grouped) {
      var rows = getVoteBreakdown(leg);
      var flat = summarizeVotes(leg);
      grouped = { floor: rows, committee: [], other: [] };
      totals = { floor: flat, committee: { proVotes: 0, antiVotes: 0, neutralVotes: 0, net: 0 }, other: { proVotes: 0, antiVotes: 0, neutralVotes: 0, net: 0 }, overall: flat };
    }

    var overall = totals.overall;
    var anyRows = grouped.floor.length + grouped.committee.length + grouped.other.length;

    var header =
      '<div class="vote-rollcalls-head">' +
        '<div class="vote-rollcalls-title">Voting Record (Roll Calls Based On Official Data)</div>' +
        '<div class="vote-totals">' +
          '<span class="vt-pro">Pro-equality: ' + overall.proVotes + '</span>' +
          '<span class="vt-anti">Anti-equality: ' + overall.antiVotes + '</span>' +
          '<span class="' + _netClass(overall.net) + '">Net impact: ' + _formatPoints(overall.net) + '</span>' +
        '</div>' +
      '</div>';

    if (!anyRows) {
      return '<div class="vote-rollcalls">' + header +
        '<div class="vote-empty">No tracked roll calls for this lawmaker yet.</div>' +
      '</div>';
    }

    var floorSection = _renderVoteSection({
      rows: grouped.floor,
      tally: totals.floor,
      kind: 'floor',
      heading: 'Floor Votes',
      tag: 'Full Chamber',
      emptyMsg: 'No floor votes recorded yet on tracked bills.'
    });
    var committeeSection = _renderVoteSection({
      rows: grouped.committee,
      tally: totals.committee,
      kind: 'committee',
      heading: 'Committee Votes',
      tag: 'In Committee',
      emptyMsg: 'No committee votes recorded for this lawmaker on tracked bills.'
    });

    // "Other" (intros, amendments) are appended only if non-empty so the
    // card stays focused; we don't show an empty placeholder for them.
    var otherSection = grouped.other.length
      ? _renderVoteSection({
          rows: grouped.other,
          tally: totals.other,
          kind: '',
          heading: 'Other Recorded Votes',
          tag: 'Procedural',
          emptyMsg: ''
        })
      : '';

    return '<div class="vote-rollcalls">' + header + floorSection + committeeSection + otherSection + '</div>';
  }

  /* ── Sponsorship breakdown (mirrors voting record shell) ──
     Pulls structured sponsorship rows for this legislator from
     scorecard-data.js. Renders one row per sponsored bill with a
     role pill, bill label + title, stance pill, and a deep link
     to the official Ohio General Assembly bill page. */
  function renderSponsorshipBreakdown(m) {
    if (typeof getLegislatorSponsorships !== 'function') return '';
    var rows = getLegislatorSponsorships(m);
    var primaryCount = 0, coCount = 0, proCount = 0, antiCount = 0;
    rows.forEach(function (r) {
      if (r.role === 'primary') primaryCount++;
      else coCount++;
      if (r.stance === 'pro') proCount++;
      else if (r.stance === 'anti') antiCount++;
    });

    var head =
      '<div class="record-block-head">' +
        '<div class="record-block-title">Bill Sponsorship (Primary &amp; Co-Sponsor)</div>' +
        '<div class="record-block-tally">' +
          '<span>Primary: <strong>' + primaryCount + '</strong></span>' +
          '<span>Co-sponsor: <strong>' + coCount + '</strong></span>' +
          (proCount  ? '<span class="vt-pro">Pro-equality: '  + proCount  + '</span>' : '') +
          (antiCount ? '<span class="vt-anti">Anti-equality: ' + antiCount + '</span>' : '') +
        '</div>' +
      '</div>';

    if (!rows.length) {
      return '<div class="record-block">' + head +
        '<div class="record-empty">No sponsorship of tracked bills on record.</div>' +
      '</div>';
    }

    var body = '';
    rows.forEach(function (r) {
      var dirClass = r.stance === 'pro' ? 'dir-pro' : (r.stance === 'anti' ? 'dir-anti' : '');
      var stanceLabel = r.stance === 'pro' ? 'Pro-equality'
                      : r.stance === 'anti' ? 'Anti-equality'
                      : 'Mixed';
      var roleLabel = r.role === 'primary' ? 'Primary' : 'Co-sponsor';
      var linkHtml = r.url
        ? '<a class="sponsor-link" href="' + r.url + '" target="_blank" rel="noopener">View bill &rarr;</a>'
        : '<span class="sponsor-link" style="opacity:.5">No link</span>';
      body +=
        '<div class="sponsor-row ' + dirClass + '">' +
          '<div class="sponsor-role ' + r.role + '">' + roleLabel + '</div>' +
          '<div class="sponsor-bill">' +
            '<div class="sb-label">' + r.bill + ' &middot; ' + r.title + '</div>' +
            '<div class="sb-sub">' + (r.ga || '') + ' General Assembly</div>' +
          '</div>' +
          '<div class="sponsor-stance ' + r.stance + '">' + stanceLabel + '</div>' +
          linkHtml +
        '</div>';
    });

    return '<div class="record-block">' + head + body + '</div>';
  }

  /* ── Grade math (high-school-level explainer) ──
     For each lawmaker: shows the three subscores with a plain-English
     description of how each one was earned, then the formula and the
     final score/grade. Uses the same computeSubscores() function that
     actually drives calcScore(), so the math always matches. */
  function _signed(x) {
    if (x > 0) return '+' + (Math.abs(x) % 1 === 0 ? x.toFixed(0) : x.toFixed(1));
    if (x < 0) return (Math.abs(x) % 1 === 0 ? x.toFixed(0) : x.toFixed(1));
    return '0';
  }
  function _subClass(x) {
    if (x > 0.05) return 'gm-num-pos';
    if (x < -0.05) return 'gm-num-neg';
    return 'gm-num-zero';
  }
  function renderGradeMath(m) {
    if (typeof computeSubscores !== 'function') return '';
    var sub = computeSubscores(m);
    var leg = _votingLegislator(m);

    /* ── Vote rows, split by stage ── */
    var voteRows = [];
    try { voteRows = (typeof getVoteBreakdown === 'function') ? getVoteBreakdown(leg) : []; }
    catch (e) { voteRows = []; }
    var floorRows = voteRows.filter(function (r) {
      var s = r.rollCall && r.rollCall.stage;
      return s === 'pass' || s === 'concur' || s === 'override';
    });
    var cmteRows  = voteRows.filter(function (r) {
      return r.rollCall && r.rollCall.stage === 'committee';
    });

    function _voteExplain(rows, label) {
      if (!rows.length) {
        return 'No tracked ' + label + ' roll calls yet. Subscore stays at 0.';
      }
      var pro = 0, anti = 0, neutral = 0, net = 0;
      rows.forEach(function (r) {
        if (r.direction === 'pro') pro++;
        else if (r.direction === 'anti') anti++;
        else neutral++;
        net += (r.points || 0);
      });
      return 'Out of <strong>' + rows.length + '</strong> tracked ' + label + ' roll calls: ' +
        '<span class="gm-pro">' + pro + ' pro-equality</span>, ' +
        '<span class="gm-anti">' + anti + ' anti-equality</span>' +
        (neutral ? ', ' + neutral + ' neutral' : '') + '. ' +
        'Net weighted impact: <strong>' + _signed(Math.round(net * 100) / 100) + '</strong> points, scaled to a &minus;5 to +5 subscore.';
    }
    var floorExplain = _voteExplain(floorRows, 'floor');
    var cmteExplain  = _voteExplain(cmteRows, 'committee');

    /* ── Bills detail ── */
    var sponsorships = [];
    try { sponsorships = (typeof getLegislatorSponsorships === 'function') ? getLegislatorSponsorships(m) : []; }
    catch (e) { sponsorships = []; }
    var primPro = 0, primAnti = 0, coPro = 0, coAnti = 0;
    sponsorships.forEach(function (s) {
      if (s.role === 'primary' && s.stance === 'pro')  primPro++;
      if (s.role === 'primary' && s.stance === 'anti') primAnti++;
      if (s.role !== 'primary' && s.stance === 'pro')  coPro++;
      if (s.role !== 'primary' && s.stance === 'anti') coAnti++;
    });
    var billsExplain;
    if (!sponsorships.length) {
      billsExplain = 'No tracked bills sponsored or co-sponsored. Subscore stays at 0.';
    } else {
      var pieces = [];
      if (primPro)  pieces.push('<span class="gm-pro">' + primPro + ' primary pro (+' + (primPro * 2) + ')</span>');
      if (coPro)    pieces.push('<span class="gm-pro">' + coPro + ' co-sponsor pro (+' + coPro + ')</span>');
      if (primAnti) pieces.push('<span class="gm-anti">' + primAnti + ' primary anti (&minus;' + (primAnti * 2) + ')</span>');
      if (coAnti)   pieces.push('<span class="gm-anti">' + coAnti + ' co-sponsor anti (&minus;' + coAnti + ')</span>');
      billsExplain = pieces.join(', ') + '. Primary sponsors carry double weight. Capped at &minus;5 to +5.';
    }

    /* v6 weights: vf*4, vc*4, s*2. Floor and committee tracked
       separately but weighted equally — both are binding action.
       Sponsorship at half weight because it signals commitment but
       not the same as a recorded yes/no on the bill itself. Added
       to a flat 50 baseline (no party calibration, no chamber
       curve), then clamped to 0-100. Same math calcScore() uses in
       scorecard-data.js, verified end-to-end. */
    var weighted = (sub.vf * 4) + (sub.vc * 4) + (sub.s * 2);

    return '' +
      '<div class="grade-math">' +
        '<div class="grade-math-head">' +
          '<h4 class="gm-title">How ' + (m.name || 'This Lawmaker') + ' Earned a ' + m.grade.grade + '</h4>' +
          '<p class="gm-subtitle">Three subscores from trackable evidence, weighted and added to a flat 50 baseline every lawmaker starts from. Floor and committee votes are binding action; sponsorship is public commitment. Same math the rest of the scorecard uses.</p>' +
        '</div>' +

        '<div class="gm-rows">' +
          '<div class="gm-row">' +
            '<div class="gm-row-head">' +
              '<span class="gm-row-label">1. Floor Votes</span>' +
              '<span class="gm-row-num ' + _subClass(sub.vf) + '">' + _signed(sub.vf) + ' <span class="gm-row-num-suffix">/ 5</span></span>' +
            '</div>' +
            '<p class="gm-row-explain">' + floorExplain + '</p>' +
          '</div>' +

          '<div class="gm-row">' +
            '<div class="gm-row-head">' +
              '<span class="gm-row-label">2. Committee Votes</span>' +
              '<span class="gm-row-num ' + _subClass(sub.vc) + '">' + _signed(sub.vc) + ' <span class="gm-row-num-suffix">/ 5</span></span>' +
            '</div>' +
            '<p class="gm-row-explain">' + cmteExplain + '</p>' +
          '</div>' +

          '<div class="gm-row">' +
            '<div class="gm-row-head">' +
              '<span class="gm-row-label">3. Bills Sponsored</span>' +
              '<span class="gm-row-num ' + _subClass(sub.s) + '">' + _signed(sub.s) + ' <span class="gm-row-num-suffix">/ 5</span></span>' +
            '</div>' +
            '<p class="gm-row-explain">' + billsExplain + '</p>' +
          '</div>' +
        '</div>' +

        '<div class="gm-formula-box">' +
          '<div class="gm-formula-line">' +
            '<strong>50</strong> ' +
            '<span class="gm-formula-baseline-tag">baseline</span> + ' +
            '(<span class="' + _subClass(sub.vf) + '">' + _signed(sub.vf) + '</span> &times; 4) + ' +
            '(<span class="' + _subClass(sub.vc) + '">' + _signed(sub.vc) + '</span> &times; 4) + ' +
            '(<span class="' + _subClass(sub.s) + '">' + _signed(sub.s) + '</span> &times; 2) = ' +
            '<strong style="color:' + m.grade.color + '">' + m.score + ' / 100</strong>' +
          '</div>' +
          '<div class="gm-formula-grade">Final grade: <strong style="color:' + m.grade.color + '">' + m.grade.grade + ' &middot; ' + m.grade.label + '</strong></div>' +
        '</div>' +

        '<p class="gm-evidence-note">All evidence below: every floor vote, every committee vote, and every bill they put their name on. Click any source to verify.</p>' +
      '</div>';
  }

  /* News & Public Statements: removed in v6.
     The score is now driven exclusively by trackable legislative
     evidence — floor votes, committee votes, and sponsorship.
     Quotes and floor speeches are too easy to spin and too hard
     to weight consistently across lawmakers. Function retained as
     a no-op stub so any older callers don't throw. */
  function renderNewsBreakdown(m) { return ''; }

  function renderCards(members) {
    var html = '';
    members.forEach(function(m, idx) {
      var gradeClass = '';
      if (m.grade.grade === 'F') gradeClass = ' grade-f';
      if (m.grade.grade === 'A+') gradeClass = ' grade-aplus';

      var partyLabel = m.party === 'D' ? 'Democrat' : 'Republican';
      var partyClass = m.party === 'D' ? 'party-d' : 'party-r';

      var bills = parseBills(m.notes);
      var billsHtml = '';
      if (bills.length > 0) {
        billsHtml = '<div class="card-bills">';
        bills.forEach(function(b) {
          var cls = b.stance === 'pro' ? 'pro' : 'anti';
          billsHtml += '<span class="bill-tag ' + cls + '">' + b.bill + ': ' + b.title + '</span>';
        });
        billsHtml += '</div>';
      }

      /* Subscore display: show actual COUNTS pulled from the
         same data sources the expanded sections render from, so
         the headline number on each card matches what the reader
         sees when they open it. v6 splits Votes into Floor and
         Committee — same buckets the score uses. */
      var floorCount = 0, cmteCount = 0;
      try {
        if (typeof getVoteBreakdown === 'function') {
          var allVotes = getVoteBreakdown(_votingLegislator(m));
          allVotes.forEach(function (r) {
            var s = r.rollCall && r.rollCall.stage;
            if (s === 'committee') cmteCount++;
            else if (s === 'pass' || s === 'concur' || s === 'override') floorCount++;
          });
        }
      } catch (e) { floorCount = 0; cmteCount = 0; }
      var sponsorCount = (typeof getLegislatorSponsorships === 'function')
        ? getLegislatorSponsorships(m).length : 0;

      /* Color the count: positive direction (pro for D-leaning record,
         anti for hostile record) doesn't apply to a raw count, so we
         just dim zeros and keep non-zeros white. */
      function _ssCls(n) { return n > 0 ? 'has' : 'zero'; }
      var fCls = _ssCls(floorCount);
      var cCls = _ssCls(cmteCount);
      var sCls = _ssCls(sponsorCount);
      var fDisp = String(floorCount);
      var cDisp = String(cmteCount);
      var sDisp = String(sponsorCount);

      html += '<div class="leg-card' + gradeClass + '" data-idx="' + idx + '">' +
        '<div class="card-collapsed">' +
          '<div class="grade-badge" style="background:' + m.grade.color + '">' + m.grade.grade + '</div>' +
          '<div class="card-center">' +
            '<div class="card-name">' + m.name + '</div>' +
            '<div class="card-meta">' + m.chamber + ' District ' + m.d + ' &middot; <span class="' + partyClass + '">' + partyLabel + '</span></div>' +
            '<div class="score-bar-wrap"><div class="score-bar-fill" style="width:' + m.score + '%;background:' + m.grade.color + '"></div></div>' +
          '</div>' +
          '<div class="card-right">' +
            '<div class="card-score-row">' +
              '<div class="card-score" style="color:' + m.grade.color + '">' + m.score + '</div>' +
              '<div class="card-score-suffix">/ 100</div>' +
            '</div>' +
            '<div class="card-grade-label" style="color:' + m.grade.color + '">' + m.grade.grade + ' &middot; ' + m.grade.label + '</div>' +
            '<div class="card-subscores">' +
              '<div class="subscore" title="Tracked floor roll calls (pass / concur / override)">Floor <span class="ss-num ' + fCls + '">' + fDisp + '</span></div>' +
              '<div class="subscore" title="Tracked committee roll calls">Cmte <span class="ss-num ' + cCls + '">' + cDisp + '</span></div>' +
              '<div class="subscore" title="Tracked bills sponsored or co-sponsored">Bills <span class="ss-num ' + sCls + '">' + sDisp + '</span></div>' +
            '</div>' +
          '</div>' +
          '<div class="card-chevron"><svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M4 6L8 10L12 6" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg></div>' +
        '</div>' +
        '<div class="card-expanded">' +
          '<div class="card-expanded-inner">' +
            renderGradeMath(m) +
            '<div class="card-notes">' + m.notes + '</div>' +
            billsHtml +
            renderVoteBreakdown(m) +
            renderSponsorshipBreakdown(m) +
          '</div>' +
        '</div>' +
      '</div>';
    });

    /* expose the rendered list so js/share.js can resolve data-idx -> member */
    window.__OPP_RENDER_MEMBERS__ = members;

    cardList.innerHTML = html;
    noResults.style.display = members.length === 0 ? 'block' : 'none';
    document.getElementById('results-count').textContent = members.length + ' result' + (members.length !== 1 ? 's' : '');

    /* Wire expand/collapse */
    var cards = cardList.querySelectorAll('.leg-card');
    cards.forEach(function(card) {
      card.addEventListener('click', function() {
        card.classList.toggle('expanded');
      });
    });

    /* Deep link: ?rep=<slug> auto-expands and scrolls to that legislator. */
    try {
      var params = new URLSearchParams(window.location.search);
      var repSlug = params.get('rep');
      if (repSlug && window.OPP_SHARE && typeof window.OPP_SHARE.slugify === 'function') {
        for (var i = 0; i < members.length; i++) {
          if (window.OPP_SHARE.slugify(members[i]) === repSlug) {
            var target = cardList.querySelector('.leg-card[data-idx="' + i + '"]');
            if (target) {
              target.classList.add('expanded');
              setTimeout(function () { target.scrollIntoView({ behavior: 'smooth', block: 'center' }); }, 80);
            }
            break;
          }
        }
      }
    } catch (e) { /* no-op: deep link is best-effort */ }
  }

  /* ── Filtering + Sorting ── */
  var filters = { search: '', chamber: 'all', party: 'all', grade: 'all' };
  var sortMode = 'score-desc';

  /* Persist filter state in the URL so a filtered view is shareable
     and survives browser refresh / back-forward navigation. */
  function _writeUrlState() {
    try {
      var url = new URL(window.location.href);
      ['search', 'chamber', 'party', 'grade'].forEach(function(k) {
        if (filters[k] && filters[k] !== 'all' && filters[k] !== '') url.searchParams.set(k, filters[k]);
        else url.searchParams.delete(k);
      });
      if (sortMode && sortMode !== 'score-desc') url.searchParams.set('sort', sortMode);
      else url.searchParams.delete('sort');
      history.replaceState(null, '', url.toString());
    } catch (e) { /* no-op */ }
  }

  function _readUrlState() {
    try {
      var params = new URLSearchParams(window.location.search);
      ['search', 'chamber', 'party', 'grade'].forEach(function(k) {
        var v = params.get(k);
        if (v !== null && v !== '') filters[k] = v;
      });
      var srt = params.get('sort');
      if (srt) sortMode = srt;
    } catch (e) { /* no-op */ }
  }

  /* Programmatic filter setters used by the chamber-tile bars. */
  function _activatePill(groupId, value) {
    var group = document.getElementById(groupId);
    if (!group) return;
    var pills = group.querySelectorAll('.pill');
    pills.forEach(function(p) {
      if (p.getAttribute('data-value') === value) p.classList.add('active');
      else p.classList.remove('active');
    });
  }
  function _setChamberFilter(value) { filters.chamber = value; _activatePill('chamber-filter', value); }
  function _setPartyFilter(value)   { filters.party   = value; _activatePill('party-filter', value); }
  function _setGradeFilter(value)   { filters.grade   = value; _activatePill('grade-filter', value); }

  window.applyFilters = function applyFilters() {
    var filtered = allMembers.filter(function(m) {
      if (filters.chamber !== 'all' && m.chamber !== filters.chamber) return false;
      if (filters.party !== 'all' && m.party !== filters.party) return false;
      if (filters.grade !== 'all' && m.grade.grade !== filters.grade) return false;
      if (filters.search) {
        var q = filters.search.toLowerCase();
        var nameMatch = m.name.toLowerCase().indexOf(q) !== -1;
        var distMatch = (m.chamber.charAt(0) + 'D' + m.d).toLowerCase().indexOf(q) !== -1 ||
                        String(m.d).indexOf(q) !== -1 ||
                        ('district ' + m.d).indexOf(q) !== -1;
        if (!nameMatch && !distMatch) return false;
      }
      return true;
    });

    filtered.sort(function(a, b) {
      switch (sortMode) {
        case 'score-desc': return b.score - a.score || a.name.localeCompare(b.name);
        case 'score-asc': return a.score - b.score || a.name.localeCompare(b.name);
        case 'name-asc': return a.name.localeCompare(b.name);
        case 'district':
          if (a.chamber !== b.chamber) return a.chamber.localeCompare(b.chamber);
          return a.d - b.d;
        default: return 0;
      }
    });

    renderCards(filtered);
    renderStats(filtered);
    _writeUrlState();
  }

  /* Pill groups */
  function setupPillGroup(id, filterKey) {
    var group = document.getElementById(id);
    var pills = group.querySelectorAll('.pill');
    pills.forEach(function(pill) {
      pill.addEventListener('click', function() {
        pills.forEach(function(p) { p.classList.remove('active'); });
        pill.classList.add('active');
        filters[filterKey] = pill.getAttribute('data-value');
        _syncStatFilterFromFilters();
        applyFilters();
      });
    });
  }
  setupPillGroup('chamber-filter', 'chamber');
  setupPillGroup('party-filter', 'party');
  setupPillGroup('grade-filter', 'grade');

  /* Stat cards double as filter buttons. Clicking "Champions" or
     "Hostile" drives the grade pill group so every control stays
     in sync; clicking the total card clears filters. */
  function _syncGradePillColors() {
    var allPill = document.querySelector('#grade-filter .pill:first-child');
    document.querySelectorAll('#grade-filter .grade-pill').forEach(function(p) {
      if (p.classList.contains('active') && !(allPill && allPill.classList.contains('active'))) {
        p.style.background = p.style.getPropertyValue('--pill-color');
        p.style.borderColor = p.style.getPropertyValue('--pill-color');
      } else {
        p.style.background = '';
        p.style.borderColor = '';
      }
    });
  }
  function _setStatFilterPressed(targetFilter) {
    document.querySelectorAll('.stat-filter').forEach(function(btn) {
      btn.setAttribute('aria-pressed', btn.getAttribute('data-filter') === targetFilter ? 'true' : 'false');
    });
  }
  function _syncStatFilterFromFilters() {
    var clean = filters.chamber === 'all' && filters.party === 'all' && !filters.search;
    if (clean && filters.grade === 'all') _setStatFilterPressed('all');
    else if (clean && filters.grade === 'A+') _setStatFilterPressed('grade:A+');
    else if (clean && filters.grade === 'F')  _setStatFilterPressed('grade:F');
    else _setStatFilterPressed(null);
  }
  document.querySelectorAll('.stat-filter').forEach(function(btn) {
    btn.addEventListener('click', function() {
      var f = btn.getAttribute('data-filter');
      if (f === 'all') {
        filters.chamber = 'all';
        filters.party = 'all';
        filters.grade = 'all';
        filters.search = '';
        _activatePill('chamber-filter', 'all');
        _activatePill('party-filter', 'all');
        _activatePill('grade-filter', 'all');
        var search = document.getElementById('search-input');
        if (search) search.value = '';
      } else if (f.indexOf('grade:') === 0) {
        var g = f.slice(6);
        filters.grade = g;
        _activatePill('grade-filter', g);
      }
      _syncGradePillColors();
      _setStatFilterPressed(f);
      applyFilters();
    });
  });

  /* Grade pill active colors */
  var gradePills = document.querySelectorAll('.grade-pill');
  gradePills.forEach(function(pill) {
    pill.addEventListener('click', function() {
      gradePills.forEach(function(p) {
        if (p.classList.contains('active')) {
          p.style.background = p.style.getPropertyValue('--pill-color');
          p.style.borderColor = p.style.getPropertyValue('--pill-color');
        } else {
          p.style.background = '';
          p.style.borderColor = '';
        }
      });
      /* Re-check the "All" pill too */
      var allPill = document.querySelector('#grade-filter .pill:first-child');
      if (allPill.classList.contains('active')) {
        gradePills.forEach(function(p) {
          p.style.background = '';
          p.style.borderColor = '';
        });
      }
    });
  });

  /* Sort */
  document.getElementById('sort-select').addEventListener('change', function() {
    sortMode = this.value;
    applyFilters();
  });

  /* Search with debounce */
  var searchTimeout;
  document.getElementById('search-input').addEventListener('input', function() {
    var val = this.value;
    clearTimeout(searchTimeout);
    searchTimeout = setTimeout(function() {
      filters.search = val;
      _syncStatFilterFromFilters();
      applyFilters();
    }, 200);
  });

  /* Clear filters chip in the stats hint. Resets every filter pill,
     clears the search box, and restores the default sort. */
  (function () {
    var resetBtn = document.getElementById('stats-reset');
    if (!resetBtn) return;
    resetBtn.addEventListener('click', function () {
      filters.chamber = 'all';
      filters.party = 'all';
      filters.grade = 'all';
      filters.search = '';
      ['chamber-filter', 'party-filter', 'grade-filter'].forEach(function (groupId) {
        var pills = document.querySelectorAll('#' + groupId + ' .pill');
        pills.forEach(function (p, i) {
          if (i === 0) {
            p.classList.add('active');
          } else {
            p.classList.remove('active');
            /* Clear inline grade-pill colors so the All pill reads cleanly. */
            if (p.classList.contains('grade-pill')) {
              p.style.background = '';
              p.style.borderColor = '';
            }
          }
        });
      });
      var search = document.getElementById('search-input');
      if (search) search.value = '';
      var sort = document.getElementById('sort-select');
      if (sort) { sort.value = 'score-desc'; sortMode = 'score-desc'; }
      _setStatFilterPressed('all');
      applyFilters();
      /* Brief tactile feedback on the chip. */
      resetBtn.style.transform = 'scale(0.92)';
      setTimeout(function () { resetBtn.style.transform = ''; }, 120);
    });
  }());

  /* Smooth-scroll the "See our scoring approach" hero link to the
     methodology section at the bottom. The CSS rule
     `.methodology-full { scroll-margin-top: 88px }` handles the offset
     so the section header lands cleanly under the sticky controls bar. */
  (function () {
    var link = document.querySelector('.hero-method-link[data-jump="methodology"]');
    if (!link) return;
    link.addEventListener('click', function (e) {
      var target = document.getElementById('methodology');
      if (!target) return;
      e.preventDefault();
      target.scrollIntoView({ behavior: 'smooth', block: 'start' });
      if (history && typeof history.replaceState === 'function') {
        history.replaceState(null, '', '#methodology');
      }
    });
  }());

  /* Keyboard shortcut: '/' focuses the search input from anywhere on the page. */
  document.addEventListener('keydown', function(e) {
    if (e.key === '/' && !e.target.matches('input, textarea, select')) {
      e.preventDefault();
      var input = document.getElementById('search-input');
      if (input) {
        input.focus();
        input.select();
      }
    }
  });

  /* ── Restore filter state from the URL before first render. ── */
  _readUrlState();
  _activatePill('chamber-filter', filters.chamber);
  _activatePill('party-filter', filters.party);
  _activatePill('grade-filter', filters.grade);
  _syncStatFilterFromFilters();
  var _searchEl = document.getElementById('search-input');
  if (_searchEl && filters.search) _searchEl.value = filters.search;
  var _sortEl = document.getElementById('sort-select');
  if (_sortEl) _sortEl.value = sortMode;

  /* ── Initial render ── */
  applyFilters();
});
